import{_ as o,o as l,c as i,ag as c}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"更新日志","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),d={name:"changelog.md"};function a(t,e,r,n,s,u){return l(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="更新日志" tabindex="-1">更新日志 <a class="header-anchor" href="#更新日志" aria-label="Permalink to &quot;更新日志&quot;">​</a></h1><p>所有重要的版本更新都会记录在此。</p><h2 id="v1-0-0-2024-01-01" tabindex="-1">v1.0.0 (2024-01-01) <a class="header-anchor" href="#v1-0-0-2024-01-01" aria-label="Permalink to &quot;v1.0.0 (2024-01-01)&quot;">​</a></h2><h3 id="首次发布" tabindex="-1">首次发布 <a class="header-anchor" href="#首次发布" aria-label="Permalink to &quot;首次发布&quot;">​</a></h3><p>ah-util 1.0.0 正式发布！</p><h4 id="新增功能" tabindex="-1">新增功能 <a class="header-anchor" href="#新增功能" aria-label="Permalink to &quot;新增功能&quot;">​</a></h4><ul><li><p><strong>类型判断模块</strong> - 提供 10 种类型判断函数</p><ul><li><code>isString</code> - 判断字符串</li><li><code>isNumber</code> - 判断数字</li><li><code>isBoolean</code> - 判断布尔值</li><li><code>isFunction</code> - 判断函数</li><li><code>isArray</code> - 判断数组</li><li><code>isObject</code> - 判断对象</li><li><code>isDate</code> - 判断日期</li><li><code>isRegExp</code> - 判断正则</li><li><code>isNil</code> - 判断空值</li><li><code>isPromise</code> - 判断 Promise</li></ul></li><li><p><strong>字符串模块</strong> - 提供 11 种字符串处理函数</p><ul><li><code>trim</code> / <code>trimAll</code> - 去除空格</li><li><code>capitalize</code> / <code>uncapitalize</code> - 首字母大小写</li><li><code>camelToKebab</code> / <code>kebabToCamel</code> / <code>snakeToCamel</code> - 命名转换</li><li><code>repeat</code> - 字符串重复</li><li><code>padStart</code> / <code>padEnd</code> - 字符串补全</li><li><code>truncate</code> - 字符串截断</li></ul></li><li><p><strong>数组模块</strong> - 提供 14 种数组处理函数</p><ul><li><code>isEmptyArray</code> - 判断空数组</li><li><code>unique</code> / <code>uniqueBy</code> - 数组去重</li><li><code>flatten</code> / <code>flattenDeep</code> - 数组扁平化</li><li><code>chunk</code> - 数组分块</li><li><code>nth</code> / <code>first</code> / <code>last</code> - 获取元素</li><li><code>intersection</code> / <code>difference</code> / <code>union</code> - 数组集合运算</li><li><code>sample</code> - 随机抽样</li><li><code>shuffle</code> - 数组洗牌</li></ul></li><li><p><strong>对象模块</strong> - 提供 9 种对象处理函数</p><ul><li><code>isEmptyObject</code> - 判断空对象</li><li><code>deepClone</code> / <code>shallowClone</code> - 对象拷贝</li><li><code>get</code> / <code>set</code> - 属性存取</li><li><code>omit</code> / <code>pick</code> - 属性筛选</li><li><code>merge</code> - 对象合并</li><li><code>toQueryString</code> - 转查询字符串</li></ul></li><li><p><strong>浏览器模块</strong> - 提供 8 种浏览器工具</p><ul><li><code>isBrowser</code> - 环境判断</li><li><code>getQueryParam</code> / <code>getAllQueryParams</code> - URL 参数解析</li><li><code>debounce</code> / <code>throttle</code> - 函数节流防抖</li><li><code>once</code> - 单次执行</li><li><code>generateId</code> - ID 生成</li><li><code>copyToClipboard</code> - 剪贴板操作</li><li><code>storage</code> - 本地存储封装</li></ul></li></ul><h4 id="特性" tabindex="-1">特性 <a class="header-anchor" href="#特性" aria-label="Permalink to &quot;特性&quot;">​</a></h4><ul><li>零依赖，体积小</li><li>完整的 TypeScript 类型定义</li><li>支持 ESM、CJS、UMD 三种导出格式</li><li>支持按需导入，Tree-shaking 友好</li><li>详细的 API 文档</li></ul>',9)])])}const g=o(d,[["render",a]]);export{h as __pageData,g as default};
